  project.stateCatalog=mapCatalogs[profile].states.map(s=>({id:s.id,name:s.name,population:s.population,provinces:s.provinces}));
  const select=$('#mapProfile'),badge=$('#mapProfileBadge');if(select)select.value=profile;if(badge){badge.className='profile-badge '+profile;badge.textContent=mapCatalogs[profile].label}
