  for(const f of project.focuses){for(const a of f.prerequisites||[])draw(a,f.id,'prerequisite');for(const a of f.visualConnections||[])draw(a,f.id,'visual');for(const a of f.mutuallyExclusive||[])if(a<f.id)draw(a,f.id,'mutual')}
