function spiritId(name){return 'NHO_idea_'+name.trim().toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'')}
function renderSpirits(){const list=$('#spiritList');if(!list)return;list.innerHTML='';for(const sp of project.nationalSpirits||[]){const x=document.createElement('div');x.className='eventitem'+(selectedSpirit===sp.id?' selected':'');x.textContent=sp.name||sp.id;x.onclick=()=>{selectedSpirit=sp.id;renderSpirits();renderSpiritEditor()};list.appendChild(x)}}
