async function renderSourceManager(){const data=await api('/api/sources'),root=$('#sourceList');root.innerHTML='';project.dependencies??=[];for(const source of data.sources||[]){const card=document.createElement('div');card.className='source-card'+(source.enabled?'':' unavailable');const counts=Object.entries(source.coverage||{}).map(([k,v])=>`${k}: ${v.status}${v.files?` (${v.files})`:''}`).join(' · ');card.innerHTML='<strong></strong><small></small><p class="hint"></p>';card.querySelector('strong').textContent=`${source.name} · ${source.layer}`;card.querySelector('small').textContent=source.enabled?'Available':'Unavailable — source package not supplied';card.querySelector('p').textContent=counts;if(source.layer!=='vanilla'){const label=document.createElement('label');label.className='checkline';label.innerHTML='<input type="checkbox"> Enable as project dependency';const input=label.querySelector('input'),existing=project.dependencies.find(x=>x.sourceId===source.id);input.checked=source.enabled&&(existing?.enabled!==false);input.disabled=!source.enabled;input.onchange=()=>{snapshot();const dependency=project.dependencies.find(x=>x.sourceId===source.id);if(dependency)dependency.enabled=input.checked;else project.dependencies.push({sourceId:source.id,name:source.name,enabled:input.checked});changed('Project dependencies updated')};card.appendChild(label)}root.appendChild(card)}if(!(data.sources||[]).length)root.innerHTML='<p class="hint">No sources have been imported on this computer.</p>'}
function renderCatalogItems(items,root,type){root.innerHTML='';for(const item of items){const row=document.createElement('div');row.className='catalog-item';row.innerHTML='<strong></strong><span></span><small></small><div class="catalog-flags"></div><button>Reference</button>';row.querySelector('strong').textContent=item.entity_id;row.querySelector('span').textContent=item.display_name;row.querySelector('small').textContent=`Source: ${item.source_mod} · File: ${item.source_file}`;const flags=row.querySelector('.catalog-flags');for(const [label,on,cls] of [['overridden',item.overridden,'override'],['conflict',item.conflict,'conflict']])if(on)flags.insertAdjacentHTML('beforeend',`<span class="catalog-flag ${cls}">${label}</span>`);row.querySelector('button').onclick=()=>{project.references??=[];if(project.references.some(x=>x.type===type&&x.targetId===item.entity_id))return showMessage('That imported ID is already referenced.');snapshot();project.references.push({type,targetId:item.entity_id,sourceId:item.source_id,sourceName:item.source_mod,sourceFile:item.source_file});changed('Imported reference added')};root.appendChild(row)}if(!items.length)root.innerHTML='<p class="hint">No matching imported definitions.</p>'}
