let downloadedUpdatePath='';
async function checkUpdates(){const dialog=$('#updateDialog');dialog.showModal();$('#updateStatus').textContent='Checking GitHub Releases…';const result=await api('/api/update/check');if(!result.ok){$('#updateVersions').textContent=`Installed version: ${result.installedVersion||'unknown'}`;$('#updateStatus').textContent=result.error||'Offline — GitHub could not be reached.';$('#updateNotes').textContent='Release information is unavailable while offline.';$('#downloadUpdate').disabled=true;return}$('#updateVersions').textContent=`Installed version: ${result.installedVersion} · Latest version: ${result.latestVersion}`;$('#updateStatus').textContent=result.updateAvailable?(result.downloadReady?'An update is available. Review the notes before downloading.':'An update exists, but its verified Windows download is unavailable.'):'You already have the latest version.';$('#updateNotes').textContent=result.releaseNotes||'No release notes were published.';$('#downloadUpdate').disabled=!(result.updateAvailable&&result.downloadReady)}
