$('#export').onclick=async()=>{const errors=validate();if(errors.length)return showMessage('Export blocked until these problems are fixed:\n\n'+errors.join('\n'));const exportPath=localPath($('#exportPath'),LOCAL_EXPORT_PATH);if(!exportPath)return showMessage('Choose an export destination first.');status.textContent='Exporting…';project.openExportFolder=$('#openExportFolder')?.checked!==false;project.exportVersion=$('#exportVersion')?.value||project.exportVersion||'v0_80';project.versionBump=$('#versionBump')?.value||'minor';const r=await api('/api/export',{...project,exportPath});if(!r.error&&r.version){project.exportVersion=r.version;$('#exportVersion').value=r.version;updateExportPreview();await saveProjectNow(true)}showMessage(r.error||`Export created:\n${r.zipPath||r.path}\n\nVersion: ${r.version}${r.opened?'\n\nThe folder was opened in File Explorer.':''}`);status.textContent=r.error?'Export failed':`Export complete · ${r.version}`};
$('#install').onclick=async()=>{const errors=validate();if(errors.length)return showMessage('Install blocked until these problems are fixed:\n\n'+errors.join('\n'));const hoi4ModFolder=localPath($('#installPath'),LOCAL_INSTALL_PATH);if(!hoi4ModFolder)return showMessage('Choose the Hearts of Iron IV mod folder first.');status.textContent='Installing test build…';const r=await api('/api/install',{...project,hoi4ModFolder});showMessage(r.error||`Test mod installed at:\n${r.path}\n\n${r.note}\n\nOpen the HOI4 launcher and enable Norway Remade`);status.textContent=r.error?'Install failed':'Test build installed'};
function validate(){const ids=new Set(),errors=[];for(const f of project.focuses){if(ids.has(f.id))errors.push('Duplicate focus ID: '+f.id);ids.add(f.id)}for(const f of project.focuses)for(const k of ['prerequisites','visualConnections','mutuallyExclusive'])for(const id of f[k]||[])if(!ids.has(id))errors.push(`${f.id} has a missing ${k} link to ${id}`);const dids=new Set();for(const d of project.decisions||[]){if(dids.has(d.id))errors.push('Duplicate decision ID: '+d.id);dids.add(d.id);if(d.linkedFocus&&!ids.has(d.linkedFocus))errors.push(`${d.id} links to missing focus ${d.linkedFocus}`)}const cids=new Set();for(const c of project.characters||[]){if(cids.has(c.id))errors.push('Duplicate character ID: '+c.id);cids.add(c.id);if(c.linkedFocus&&!ids.has(c.linkedFocus))errors.push(`${c.id} links to missing focus ${c.linkedFocus}`);if(c.linkedDecision&&!dids.has(c.linkedDecision))errors.push(`${c.id} links to missing decision ${c.linkedDecision}`)}
 const catalog=new Map((project.stateCatalog||[]).map(s=>[Number(s.id),s]));for(const f of project.focuses)for(const e of f.effects||[]){if(e.category!=='state')continue;if(e.mapProfile&&e.mapProfile!==project.mapProfile)errors.push(`${f.name||f.id}: state reward was made for ${profileLabel(e.mapProfile)}, but project uses ${profileLabel(project.mapProfile)}`);let s=catalog.get(Number(e.state));if(!s&&e.stateName){const wanted=String(e.stateName).trim().toLowerCase();const matches=[...catalog.values()].filter(x=>String(x.name).trim().toLowerCase()===wanted);if(matches.length===1){s=matches[0];e.state=s.id;e.population=s.population}}if(!s)errors.push(`${f.name||f.id}: state ${e.state} does not exist in ${profileLabel(project.mapProfile)}`);else if(e.province&&!s.provinces.includes(Number(e.province)))errors.push(`${f.name||f.id}: province ${e.province} is not inside ${s.name} on ${profileLabel(project.mapProfile)}`)}return errors}
$('#undo').onclick=()=>{if(!history.length)return;future.push(JSON.stringify(project));project=JSON.parse(history.pop());selected=null;changed('Undo');renderEditor();renderEvents();renderDecisions();renderCharacters();renderSpirits();renderSpiritEditor()};$('#redo').onclick=()=>{if(!future.length)return;history.push(JSON.stringify(project));project=JSON.parse(future.pop());selected=null;changed('Redo');renderEditor();renderEvents();renderDecisions();renderCharacters();renderSpirits();renderSpiritEditor()};
